		'Name "RequirementLabel"',
		'Name "RequirementValue"',
		'Name "ProgressLabel"',
		'Name "ProgressValue"',
		'Name "RewardLabel"',
		'Name "RewardValue"',
		'Name "FailureLabel"',
		'Name "FailureValue"',
		'Name "ObjectivesTitle"',
		'Name "ObjectiveScroll"',
		'Name "ObjectiveItems"',
