}
foreach ($forbiddenReportDialogLayoutEntry in @(
		"CloseBody",
		"CloseBackground",
		"ButtonWidgetSlot",
		"OffsetBottom 5",
		"OffsetBottom 58",
		"OffsetBottom 94",
		"OffsetBottom 62"
