	$schema62MethodMatches = [regex]::Matches($schema62ScriptText, $schema62MethodPattern)
	foreach ($schema62OwnerAssignment in $schema62OwnerAssignments) {
		$schema62ApprovedOwnerWrite = $false
		$schema62EnclosingMethod = ""
