			}
			$schema62EnclosingMethod = $schema62MethodMatch.Groups[1].Value
		}
		if ($schema62ScriptFile.Name -eq "HST_DefaultCatalog.c" -or
			$schema62ScriptFile.Name -match 'ProofService\.c$' -or
