		$approvedLegacyConstant = $profileScriptRelativePath -eq $profilePathServicePath -and
			$profileScriptLine -match ('^\s*static const string LEGACY_[A-Z0-9_]+\s*=\s*"' + $legacyProfileLiteralPattern + '(?:/[^\"]*)?";\s*$')
		if (!$approvedLegacyConstant) {
