		'PartisanGuard'
	$guardedWorkbenchSelfTestGuard = $guardedWorkbenchSelfTestGuardBase +
		[IO.Path]::DirectorySeparatorChar + 'nonce'
	$guardedWorkbenchSelfTestProjectDirectory =
