			-ExpectedProjectId 'partisan_selftest' `
			-ExpectedProjectGuid '0123456789abcdef' `
			-GuardRoot $Guard `
			-ResolvedAddonRoots @($Addon)
	} ($guardedWorkbenchSelfTestLines -join "`r`n") `
