	'[string]::IsNullOrWhiteSpace([string]$processRow.CommandLine)',
	'Test-ExactNativeArgumentVector',
	'-CommandLine ([string]$processRow.CommandLine)',
	'-ExpectedExecutable $ExpectedExecutable',
	'-ExpectedArguments $ExpectedArguments',
