foreach ($ordinaryProofCheckpointSaveTypeEntry in @(
		'SaveGameManager saveManager = SaveGameManager.Get();',
		'ESaveGameType requiredSaveTypes = ESaveGameType.MANUAL',
		'| ESaveGameType.AUTO',
		'| ESaveGameType.SCRIPTED',
		'| ESaveGameType.SHUTDOWN;',
