}
$ordinaryRunnerInvokeStageBlock = Get-ScriptMethodBlock `
	$ordinaryPersistenceRunnerText 'function Invoke-OrdinaryCampaignStage'
foreach ($ordinaryStandardServerEntry in @(
		'$expectedServerLeaf = "ArmaReforgerServer.exe"',
